INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Medicine_Ball_Chest_Pass','Medicine Ball Chest Pass','pecho',ARRAY['hombros','tríceps'],'balón medicinal','plyometrics',ARRAY['You will need a partner for this exercise. Lacking one, this movement can be performed against a wall.','Begin facing your partner holding the medicine ball at your torso with both hands.','Pull the ball to your chest, and reverse the motion by extending through the elbows. For sports applications, you can take a step as you throw.','Your partner should catch the ball, and throw it back to you.','Receive the throw with both hands at chest height.'],'You will need a partner for this exercise. Lacking one, this movement can be performed against a wall. Begin facing your partner holding the medicine ball at your torso with both hands. Pull the ball to your chest, and reverse the motion by extending through the elbows. For sports applications, you can take a step as you throw. Your partner should catch the ball, and throw it back to you. Receive the throw with both hands at chest height.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Medicine_Ball_Chest_Pass/0.jpg','exercisedb',true),('Medicine_Ball_Full_Twist','Medicine Ball Full Twist','abdominales',ARRAY['hombros'],'balón medicinal','plyometrics',ARRAY['For this exercise you will need a medicine ball and a partner. Stand back to back with your partner, spaced 2-3 feet apart. This will be your starting position.','Hold the ball in front of the trunk. Open the hips and turn the shoulders at the same time as your partner.','For full rotation, you and your partner should twist in the same direction, i.e. counter-clockwise.','Pass the ball to your partner, and both of you can now twist in the opposite direction to repeat the procedure.'],'For this exercise you will need a medicine ball and a partner. Stand back to back with your partner, spaced 2-3 feet apart. This will be your starting position. Hold the ball in front of the trunk. Open the hips and turn the shoulders at the same time as your partner. For full rotation, you and your partner should twist in the same direction, i.e. counter-clockwise. Pass the ball to your partner, and both of you can now twist in the opposite direction to repeat the procedure.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Medicine_Ball_Full_Twist/0.jpg','exercisedb',true),('Medicine_Ball_Scoop_Throw','Medicine Ball Scoop Throw','hombros',ARRAY['abdominales','isquiotibiales','cuádriceps'],'balón medicinal','plyometrics',ARRAY['Assume a semisquat stance with a medicine ball in your hands. Your arms should hang so the ball is near your feet.','Begin by thrusting the hips forward as you extend through the legs, jumping up.','As you do, swing your arms up and over your head, keeping them extended, releasing the ball at the peak of your movement. The goal is to throw the ball the greatest distance behind you.'],'Assume a semisquat stance with a medicine ball in your hands. Your arms should hang so the ball is near your feet. Begin by thrusting the hips forward as you extend through the legs, jumping up. As you do, swing your arms up and over your head, keeping them extended, releasing the ball at the peak of your movement. The goal is to throw the ball the greatest distance behind you.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Medicine_Ball_Scoop_Throw/0.jpg','exercisedb',true),('Middle_Back_Shrug','Middle Back Shrug','espalda media',ARRAY[]::text[],'mancuernas','strength',ARRAY['Lie facedown on an incline bench while holding a dumbbell in each hand. Your arms should be fully extended hanging down and pointing towards the floor. The palms of your hands should be facing each other. This will be your starting position.','As you exhale, squeeze your shoulder blades together and hold the contraction for a full second. Tip: This movement is just like the reverse action of a hug, or trying to perform rear laterals as if you had no arms.','As you inhale go back to the starting position.','Repeat for the recommended amount of repetitions.'],'Lie facedown on an incline bench while holding a dumbbell in each hand. Your arms should be fully extended hanging down and pointing towards the floor. The palms of your hands should be facing each other. This will be your starting position. As you exhale, squeeze your shoulder blades together and hold the contraction for a full second. Tip: This movement is just like the reverse action of a hug, or trying to perform rear laterals as if you had no arms. As you inhale go back to the starting position. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Middle_Back_Shrug/0.jpg','exercisedb',true),('Middle_Back_Stretch','Middle Back Stretch','espalda media',ARRAY['abdominales','dorsales','espalda baja'],NULL,'stretching',ARRAY['Stand so your feet are shoulder width apart and your hands are on your hips.','Twist at your waist until you feel a stretch. Hold for 10 to 15 seconds, then twist to the other side.'],'Stand so your feet are shoulder width apart and your hands are on your hips. Twist at your waist until you feel a stretch. Hold for 10 to 15 seconds, then twist to the other side.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Middle_Back_Stretch/0.jpg','exercisedb',true),('Mixed_Grip_Chin','Mixed Grip Chin','espalda media',ARRAY['bíceps','dorsales'],'otro','strength',ARRAY['Using a spacing that is just about 1 inch wider than shoulder width, grab a pull-up bar with the palms of one hand facing forward and the palms of the other hand facing towards you. This will be your starting position.','Now start to pull yourself up as you exhale. Tip: With the arm that has the palms facing up concentrate on using the back muscles in order to perform the movement. The elbow of that arm should remain close to the torso. With the other arm that has the palms facing forward, the elbows will be away but in line with the torso. You will concentrate on using the lats to pull your body up.','After a second contraction at the top, start to slowly come down as you inhale.','Repeat for the recommended amount of repetitions.','On the following set, switch grips; so if you had the right hand with the palms facing you and the left one with the palms facing forward, on the next set you will have the palms facing forward for the right hand and facing you for the left.'],'Using a spacing that is just about 1 inch wider than shoulder width, grab a pull-up bar with the palms of one hand facing forward and the palms of the other hand facing towards you. This will be your starting position. Now start to pull yourself up as you exhale. Tip: With the arm that has the palms facing up concentrate on using the back muscles in order to perform the movement. The elbow of that arm should remain close to the torso. With the other arm that has the palms facing forward, the elbows will be away but in line with the torso. You will concentrate on using the lats to pull your body up. After a second contraction at the top, start to slowly come down as you inhale. Repeat for the recommended amount of repetitions. On the following set, switch grips; so if you had the right hand with the palms facing you and the left one with the palms facing forward, on the next set you will have the palms facing forward for the right hand and facing you for the left.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Mixed_Grip_Chin/0.jpg','exercisedb',true),('Monster_Walk','Monster Walk','abductores',ARRAY[]::text[],'bandas elásticas','strength',ARRAY['Place a band around both ankles and another around both knees. There should be enough tension that they are tight when your feet are shoulder width apart.','To begin, take short steps forward alternating your left and right foot.','After several steps, do just the opposite and walk backward to where you started.'],'Place a band around both ankles and another around both knees. There should be enough tension that they are tight when your feet are shoulder width apart. To begin, take short steps forward alternating your left and right foot. After several steps, do just the opposite and walk backward to where you started.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Monster_Walk/0.jpg','exercisedb',true),('Mountain_Climbers','Mountain Climbers','cuádriceps',ARRAY['pecho','isquiotibiales','hombros'],NULL,'plyometrics',ARRAY['Begin in a pushup position, with your weight supported by your hands and toes. Flexing the knee and hip, bring one leg until the knee is approximately under the hip. This will be your starting position.','Explosively reverse the positions of your legs, extending the bent leg until the leg is straight and supported by the toe, and bringing the other foot up with the hip and knee flexed. Repeat in an alternating fashion for 20-30 seconds.'],'Begin in a pushup position, with your weight supported by your hands and toes. Flexing the knee and hip, bring one leg until the knee is approximately under the hip. This will be your starting position. Explosively reverse the positions of your legs, extending the bent leg until the leg is straight and supported by the toe, and bringing the other foot up with the hip and knee flexed. Repeat in an alternating fashion for 20-30 seconds.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Mountain_Climbers/0.jpg','exercisedb',true),('Moving_Claw_Series','Moving Claw Series','isquiotibiales',ARRAY['pantorrillas','cuádriceps'],NULL,'plyometrics',ARRAY['This move helps prepare your running form to help you excel at sprinting. As you run, be sure to flex the knee, aiming to kick your glutes as the hip extends.','Reload the quad as the leg moves back forward, attacking the ground on the next step.','Ensure that as you run, you block with the arms, punching through in a rapid 1-2 motion.'],'This move helps prepare your running form to help you excel at sprinting. As you run, be sure to flex the knee, aiming to kick your glutes as the hip extends. Reload the quad as the leg moves back forward, attacking the ground on the next step. Ensure that as you run, you block with the arms, punching through in a rapid 1-2 motion.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Moving_Claw_Series/0.jpg','exercisedb',true),('Muscle_Snatch','Muscle Snatch','isquiotibiales',ARRAY['glúteos','espalda baja','cuádriceps','hombros','tríceps'],'barra','olympic weightlifting',ARRAY['Begin with a loaded barbell held at the mid thigh position with a wide grip. The feet should be directly below the hips, with the feet turned out as needed. Lower the hips, with the chest up and the head looking forward. The shoulders should be just in front of the bar. This will be the starting position.','Begin the pull by driving through the front of the heels, raising the bar. Transition into the second pull by extending through the hips knees and ankles, driving the bar up as quickly as possible. The bar should be close to the body.','Continue raising the bar to the overhead position, without rebending the knees.'],'Begin with a loaded barbell held at the mid thigh position with a wide grip. The feet should be directly below the hips, with the feet turned out as needed. Lower the hips, with the chest up and the head looking forward. The shoulders should be just in front of the bar. This will be the starting position. Begin the pull by driving through the front of the heels, raising the bar. Transition into the second pull by extending through the hips knees and ankles, driving the bar up as quickly as possible. The bar should be close to the body. Continue raising the bar to the overhead position, without rebending the knees.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Muscle_Snatch/0.jpg','exercisedb',true);